// A pipe AGGREGATE step (|> AGGREGATE ...) can be immediately followed by a plain
// GROUP BY clause, which is parsed as an ordinary <other_clause>.
// Here we fold that trailing GROUP BY clause into the preceding AGGREGATE
// pipe-operator node, as its nested groupBy sub-clause.
const mergePipeAggregateGroupBy = (clauses: AstNode[]): AstNode[] => {
  const result: AstNode[] = [];
  for (const clause of clauses) {
    const prev = result[result.length - 1];
    if (
      prev &&
      prev.type === NodeType.pipe_operator &&
      prev.nameKw.text === 'AGGREGATE' &&
      !prev.groupBy &&
      clause.type === NodeType.clause &&
      clause.nameKw.text === 'GROUP BY'
