  describe('BigQuery pipe query syntax', () => {
    it('formats a chain of standard pipe clauses', () => {
      const result = format(
        'FROM table |> WHERE x > 1 |> SELECT a, b |> ORDER BY a |> LIMIT 10;'
      );
      expect(result).toBe(dedent`
        FROM
          table
        |> WHERE
          x > 1
        |> SELECT
          a,
          b
        |> ORDER BY
          a
        |> LIMIT 10;
      `);
    });

    it('formats pipe SELECT *', () => {
      const result = format('FROM t |> SELECT *;');
      expect(result).toBe(dedent`
